marfan_notes = json.load(open('selected_notes.json'))

def generate_prompts(
    prompt_id="prompt8",
    use_shot=True,
    shot_id="prompt8-shot-group-ab",
):
    few_shot_template = ""
    if use_shot:
        for shot in shot_examples[shot_id]:
            few_shot_template += (
                "=============\n"
                f"{prompts[prompt_id]}\n\n"
                f"**Patient's Medical Progress Note**: {shot['note']}\n\n"
                f"**Evaluation**: {shot['evaluation']}\n"
            )
    prompts_all = []
    for note_entry in marfan_notes:
        note, label = note_entry['summary'], note_entry['label']
        note = note.replace("\n\n", "\n")
        prompt = few_shot_template + (
            "=============\n"
            f"{prompts[prompt_id]}\n\n"
            f"**Patient's Medical Progress Note**: {note}\n\n"
            "**Evaluation**: "
        )
        prompts_all.append({
            "prmopt": prompt,
            "label": label,
            "note_id": note_entry["note_id"]
        })

    output_filename = f"{shot_id}.json" if use_shot else f"{prompt_id}-0-shot.json"
    with open(f'prompts_final/{output_filename}', 'w') as f:
        json.dump(prompts_all, f, indent=4)

